import Foundation

// MARK: - Environment Configuration

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev-api.example.com"
        case .staging:
            return "https://staging-api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

// MARK: - Network Errors

enum NetworkError: LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case serverError(statusCode: Int, message: String?)
    case unauthorized
    case networkFailure(Error)
    case unknown
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received from server"
        case .decodingError(let error):
            return "Failed to decode response: \(error.localizedDescription)"
        case .serverError(let statusCode, let message):
            return "Server error (\(statusCode)): \(message ?? "Unknown")"
        case .unauthorized:
            return "Unauthorized. Please log in again."
        case .networkFailure(let error):
            return "Network failure: \(error.localizedDescription)"
        case .unknown:
            return "An unknown error occurred"
        }
    }
}

// MARK: - HTTP Method

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case delete = "DELETE"
}

// MARK: - API Endpoint

struct Endpoint {
    let path: String
    let method: HTTPMethod
    let headers: [String: String]?
    let body: Data?
    let queryItems: [URLQueryItem]?
    
    init(
        path: String,
        method: HTTPMethod = .get,
        headers: [String: String]? = nil,
        body: Data? = nil,
        queryItems: [URLQueryItem]? = nil
    ) {
        self.path = path
        self.method = method
        self.headers = headers
        self.body = body
        self.queryItems = queryItems
    }
}

// MARK: - API Endpoints Factory

enum APIEndpoint {
    
    // Authentication
    static func login(email: String, password: String) -> Endpoint {
        let body = LoginRequest(email: email, password: password)
        let bodyData = try? JSONEncoder().encode(body)
        return Endpoint(
            path: "/auth/login",
            method: .post,
            body: bodyData
        )
    }
    
    static func register(name: String, email: String, password: String) -> Endpoint {
        let body = RegisterRequest(name: name, email: email, password: password)
        let bodyData = try? JSONEncoder().encode(body)
        return Endpoint(
            path: "/auth/register",
            method: .post,
            body: bodyData
        )
    }
    
    static func refreshToken(refreshToken: String) -> Endpoint {
        let body = RefreshTokenRequest(refreshToken: refreshToken)
        let bodyData = try? JSONEncoder().encode(body)
        return Endpoint(
            path: "/auth/refresh",
            method: .post,
            body: bodyData
        )
    }
    
    // User Data
    static func getCurrentUser() -> Endpoint {
        return Endpoint(path: "/users/me", method: .get)
    }
    
    static func getUser(id: String) -> Endpoint {
        return Endpoint(path: "/users/\(id)", method: .get)
    }
    
    static func getUsers(page: Int = 1, limit: Int = 20) -> Endpoint {
        return Endpoint(
            path: "/users",
            method: .get,
            queryItems: [
                URLQueryItem(name: "page", value: "\(page)"),
                URLQueryItem(name: "limit", value: "\(limit)")
            ]
        )
    }
    
    static func updateUser(id: String, update: UserUpdateRequest) -> Endpoint {
        let bodyData = try? JSONEncoder().encode(update)
        return Endpoint(
            path: "/users/\(id)",
            method: .put,
            body: bodyData
        )
    }
}

