// MARK: - Token Storage

protocol TokenStorage {
    func saveTokens(accessToken: String, refreshToken: String)
    func getAccessToken() -> String?
    func getRefreshToken() -> String?
    func clearTokens()
}

final class KeychainTokenStorage: TokenStorage {
    
    static let shared = KeychainTokenStorage()
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    private init() {}
    
    func saveTokens(accessToken: String, refreshToken: String) {
        save(key: accessTokenKey, value: accessToken)
        save(key: refreshTokenKey, value: refreshToken)
    }
    
    func getAccessToken() -> String? {
        return load(key: accessTokenKey)
    }
    
    func getRefreshToken() -> String? {
        return load(key: refreshTokenKey)
    }
    
    func clearTokens() {
        delete(key: accessTokenKey)
        delete(key: refreshTokenKey)
    }
    
    // MARK: - Keychain Helpers
    
    private func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }
    
    private func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Codable>(_ endpoint: Endpoint) async throws -> T
    func request<T: Codable>(_ endpoint: Endpoint) async throws -> APIResponse<T>
}

// MARK: - Network Client

final class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let environment: Environment
    private let tokenStorage: TokenStorage
    private let decoder: JSONDecoder
    
    private var isRefreshing = false
    private var refreshContinuations: [CheckedContinuation<String, Error>] = []
    private let lock = NSLock()
    
    init(
        environment: Environment = .currentEnvironment,
        session: URLSession = .shared,
        tokenStorage: TokenStorage = KeychainTokenStorage.shared
    ) {
        self.environment = environment
        self.session = session
        self.tokenStorage = tokenStorage
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
    }
    
    // MARK: - Public Methods
    
    func request<T: Codable>(_ endpoint: Endpoint) async throws -> T {
        let data = try await performRequest(endpoint)
        do {
            let decoded = try decoder.decode(T.self, from: data)
            return decoded
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
    
    func request<T: Codable>(_ endpoint: Endpoint) async throws -> APIResponse<T> {
        let data = try await performRequest(endpoint)
        do {
            let decoded = try decoder.decode(APIResponse<T>.self, from: data)
            return decoded
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
    
    // MARK: - Private Methods
    
    private func performRequest(_ endpoint: Endpoint, isRetry: Bool = false) async throws -> Data {
        guard var urlComponents = URLComponents(string: environment.baseURL + endpoint.path) else {
            throw NetworkError.invalidURL
        }
        
        urlComponents.queryItems = endpoint.queryItems
        
        guard let url = urlComponents.url else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.httpBody = endpoint.body
        request.timeoutInterval = 30
        
        // Default headers
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Auth token
        if let accessToken = tokenStorage.getAccessToken() {
            request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
        }
        
        // Custom headers
        endpoint.headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            throw NetworkError.networkFailure(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown
        }
        
        // Handle token refresh on 401
        if httpResponse.statusCode == 401 && !isRetry {
            _ = try await refreshAccessToken()
            return try await performRequest(endpoint, isRetry: true)
        }
        
        try validateResponse(httpResponse, data: data)
        
        return data
    }
    
    private func validateResponse(_ response: HTTPURLResponse, data: Data) throws {
        switch response.statusCode {
        case 200...299:
            return
        case 401:
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        default:
            let message = try? decoder.decode(APIResponse<String>.self, from: data).error
            throw NetworkError.serverError(statusCode: response.statusCode, message: message)
        }
    }
    
    private func refreshAccessToken() async throws -> String {
        lock.lock()
        
        if isRefreshing {
            lock.unlock()
            return try await withCheckedThrowingContinuation { continuation in
                lock.lock()
                refreshContinuations.append(continuation)
                lock.unlock()
            }
        }
        
        isRefreshing = true
        lock.unlock()
        
        defer {
            lock.lock()
            isRefreshing = false
            lock.unlock()
        }
        
        guard let refreshToken = tokenStorage.getRefreshToken() else {
            resumeWaitingContinuations(with: .failure(NetworkError.unauthorized))
            throw NetworkError.unauthorized
        }
        
        let endpoint = APIEndpoint.refreshToken(refreshToken: refreshToken)
        
        guard var urlComponents = URLComponents(string: environment.baseURL + endpoint.path) else {
            throw NetworkError.invalidURL
        }
        urlComponents.queryItems = endpoint.queryItems
        
        guard let url = urlComponents.url else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.httpBody = endpoint.body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            let (data, response) = try await session.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse,
                  (200...299).contains(httpResponse.statusCode) else {
                tokenStorage.clearTokens()
                resumeWaitingContinuations(with: .failure(NetworkError.unauthorized))
                throw NetworkError.unauthorized
            }
            
            let authResponse = try decoder.decode(APIResponse<AuthResponse>.self, from: data)
            
            guard let auth = authResponse.data else {
                tokenStorage.clearTokens()
                resumeWaitingContinuations(with: .failure(NetworkError.unauthorized))
                throw NetworkError.unauthorized
            }
            
            tokenStorage.saveTokens(accessToken: auth.accessToken, refreshToken: auth.refreshToken)
            resumeWaitingContinuations(with: .success(auth.accessToken))
            return auth.accessToken
            
        } catch let error as NetworkError {
            resumeWaitingContinuations(with: .failure(error))
            throw error
        } catch {
            resumeWaitingContinuations(with: .failure(NetworkError.networkFailure(error)))
            throw NetworkError.networkFailure(error)
        }
    }
    
    private func resumeWaitingContinuations(with result: Result<String, Error>) {
        lock.lock()
        let continuations = refreshContinuations
        refreshContinuations.removeAll()
        lock.unlock